import FormInputGroup   from "Components/Global/FormInputGroup";
import AddressFormInpts from "../AddressFormInpts";

const addresApplicantSection = [
	{name : "applicant.address.street",       label : "Calle",  placeholder : "Av. de las Americas"},
	{name : "applicant.address.outer_number", label : "No. Ext", placeholder : "123"},
	{name : "applicant.address.inner_number", label : "No. Interior (Opcional)", placeholder : "Apto. 123"},
	{name : "applicant.address.zip_code",     label : "C.P.", placeholder : "12345"},
	{name : "applicant.address.colony",       label : "Colonia", placeholder : "Selecciona una colonia"},
	{name : "applicant.address.municipality", label : "Delegación o Municipio", placeholder : "Centro"},
];

const ApplicantFormSection = ({ hookForm, inptsRules}) => {
	return (
		<div className="w-100">
			<h1 className="title">Solicitante</h1>
			<FormInputGroup
				name="applicant.paternal_surname"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Apellido Paterno"
				placeholder="Rodríguez"
				options={inptsRules}
			/>
			<FormInputGroup
				name="applicant.maternal_surname"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Apellido Materno"
				placeholder="Vásquez"
				options={inptsRules}
			/>
			<FormInputGroup
				name="applicant.name"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Nombre(s)"
				placeholder="Ismael"
				options={inptsRules}
			/>
			<FormInputGroup
				name="applicant.rfc"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="RFC"
				placeholder="ROVI123456123"
				options={{
					...inptsRules,
					pattern : {
						value   : /^[A-Z]{4}[0-9]{6}[A-Z0-9]{3}$/i,
						message : "RFC inválido",
					},
				}}
			/>
			<FormInputGroup
				name="applicant.nss"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="NSS"
				placeholder="12345678910"
				options={{
					...inptsRules,
					pattern : {
						value   : /^[0-9]{11}$/i,
						message : "NSS inválido",
					},
				}}
			/>
			<FormInputGroup
				name="applicant.curp"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="CURP"
				placeholder="ROVI490617HSPDSS05"
				options={{
					...inptsRules,
					pattern : {
						value   : /^[A-Z]{4}[0-9]{6}[H|M]{1}[A-Z]{5}[0-9]{2}$/i,
						message : "CURP inválido",
					},
				}}
			/>
			<AddressFormInpts
				zipCodeKey="applicant.address.zip_code"
				municipalityKey="applicant.address.municipality"
				settlementTypeKey="applicant.address.colony"
				hookForm={hookForm}
				inptsRules={inptsRules}
				inptsValues={addresApplicantSection}
			/>
		</div>
	);
};

export default ApplicantFormSection;
