import { DollarSign } from "react-feather";

//Our Imports
import { isValidArray } from "Helpers";
import FormCreatable    from "Components/Global/FormCreatable";
import FormInputGroup   from "Components/Global/FormInputGroup";
import FormSelectGroup  from "Components/Global/FormSelectGroup";

import {
	roomOptions,
	levelOptions,
	zoneTypeOptions,
	typologyOptions,
	roadTypeOptions,
	livingPlaceOptions,
	settlementTypeOptions,
} from "Resources/data/RequestForm";


const LivingPlaceFormSection = ({
	delegations : {
		type,
		hookForm,
		inptsRules,
		placesOptions,
		settlementOptions,
	},
}) => {

	const addresLivingPlaceSection = [
		{name : "housing.street_type",  label : "Tipo de Vialidad", placeholder : "Selecciona el tipo", options : roadTypeOptions},
		{name : "housing.zone_type",    label : "Tipo de Zona", placeholder : "Selecciona el tipo", options : zoneTypeOptions},
		{name : "housing.section",      label : "Super Manzana", placeholder : "Super Manzana"},
		{name : "housing.sub_section",  label : "Manzana", placeholder : "Manzana"},
		{name : "housing.lot",          label : "Lote (máx. 5 carácteres)", placeholder : "Lote", maxLength : 5},
		{name : "housing.outer_number", label : "No. Exterior", placeholder : "123"},
		{name : "housing.inner_number", label : "No. Interiror (Opcional)", placeholder : "123"},
		{name : "housing.house_type",   label : "Tipo de vivienda", options : livingPlaceOptions, placeholder : "Selecciona el tipo"},
	];

	return (
		<div className="mt-1">
			<h1 className="title">Vivienda {type}</h1>
			<FormInputGroup
				name="housing.zip_code"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Código Postal"
				placeholder="45678"
				maxLength="5"
				options={inptsRules}
			/>
			<FormSelectGroup
				name="housing.id_place"
				placeholder="Selecciona la Entidad Federativa"
				label="Entidad Federativa"
				options={placesOptions ? placesOptions : []}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormInputGroup
				name="housing.municipality"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Delegación o Municipio"
				placeholder="Zapopan"
				options={inptsRules}
			/>
			<FormInputGroup
				name="housing.town"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Localidad"
				placeholder="Localidad"
				options={inptsRules}
			/>
			<FormCreatable
				name="housing.settlement"
				isDisabled={!isValidArray(settlementOptions)}
				label="Nombre del Asentamiento"
				placeholder="Selecciona un Asentamiento"
				options={settlementOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormSelectGroup
				name="housing.settlement_type"
				placeholder="Selecciona un Tipo de Asentamiento"
				label="Tipo de Asentamiento"
				options={settlementTypeOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<hr />
			<FormInputGroup
				name="housing.street_name"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Nombre Vialidad / Calle"
				placeholder="Juárez"
				options={inptsRules}
			/>
			{
				addresLivingPlaceSection.map((item) => {
					return (
						item?.options ?
							<FormSelectGroup
								key={item.name}
								name={item.name}
								placeholder={item.placeholder}
								label={item.label}
								options={item.options}
								hookForm={hookForm}
								errors={hookForm.formState.errors}
								menuPortalTarget={document.body}
								rules={inptsRules}
							/>
							:
							<FormInputGroup
								key={item.name}
								name={item.name}
								type={item?.type ? item.type : "text"}
								maxLength={item?.maxLength}
								register={hookForm.register}
								errors={hookForm.formState.errors}
								label={item?.label}
								placeholder={item?.placeholder}
								options={inptsRules}
							/>
					);
				})
			}
			<hr />
			<h5 className="sub-title">Vialidad</h5>
			<FormInputGroup
				name="housing.street_between_1_name"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Primera Entrevialidad"
				placeholder="Juárez"
				options={inptsRules}
			/>
			<FormSelectGroup
				name="housing.street_between_1_type"
				placeholder="Selecciona un Tipo de Vialidad"
				label="Tipo de Vialidad"
				options={roadTypeOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormInputGroup
				name="housing.street_between_2_name"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Segunda Entrevialidad"
				placeholder="González Ortega"
				options={inptsRules}
			/>
			<FormSelectGroup
				name="housing.street_between_2_type"
				placeholder="Selecciona un Tipo de Vialidad"
				label="Tipo de Vialidad"
				options={roadTypeOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormInputGroup
				name="housing.street_back_name"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				placeholder="Privada de las Flores"
				label="Vialidad Posterior"
				options={inptsRules}

			/>
			<FormSelectGroup
				name="housing.street_back_type"
				placeholder="Selecciona un Tipo de Vialidad"
				label="Tipo de Vialidad"
				options={roadTypeOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormInputGroup
				name="housing.reference"
				type="textarea"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Referencia"
				placeholder="Escriba aquí la referencia del domicilio"
				options={inptsRules}
			/>
			<FormInputGroup
				name="housing.lat"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Latitud"
				placeholder="456.234"
				options={inptsRules}
			/>
			<FormInputGroup
				name="housing.lng"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Longitud"
				placeholder="456.234"
				options={inptsRules}
			/>
			<FormSelectGroup
				name="housing.typology"
				placeholder="Selecciona una opción"
				label="Tipologia"
				options={typologyOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormSelectGroup
				name="housing.level"
				placeholder="Selecciona una opción"
				label="Nivel"
				options={levelOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormInputGroup
				name="housing.construction_area"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Area de Construcción"
				placeholder="Area de Construcción"
				options={inptsRules}
			/>
			<FormInputGroup
				name="housing.land_area"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Area de Terreno"
				placeholder="Area de Terreno"
				options={inptsRules}
			/>
			<FormSelectGroup
				name="housing.number_rooms"
				placeholder="Selecciona una opción"
				label="No. de Recámaras"
				options={roomOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormSelectGroup
				name="housing.number_bathrooms"
				placeholder="Selecciona una opción"
				label="No. de Baños"
				options={roomOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormSelectGroup
				name="housing.parking_lot"
				placeholder="Selecciona una opción"
				label="No. de Estacionamientos"
				options={roomOptions}
				hookForm={hookForm}
				errors={hookForm.formState.errors}
				menuPortalTarget={document.body}
				rules={inptsRules}
			/>
			<FormInputGroup
				type="number"
				name="housing.approximate_value"
				icon={<DollarSign size={15} />}
				register={hookForm.register}
				errors={hookForm.formState.errors}
				label="Monto de la Acción"
				placeholder="00.00"
				options={inptsRules}
			/>
		</div>
	);
};

export default LivingPlaceFormSection;
